%#codegen
function y = Conv_fixpt(x, W)

fm = get_fimath();

[fmo_1, fmo_2, fmo_3] = size(W);
wrow = fi(fmo_1, 0, 4, 0, fm);
wcol = fi(fmo_2, 0, 4, 0, fm);
numFilters = fi(fmo_3, 0, 5, 0, fm);
[fmo_4, fmo_5, ~         ] = size(x);
xrow = fi(fmo_4, 0, 5, 0, fm);
xcol = fi(fmo_5, 0, 5, 0, fm);

yrow = fi(fi_signed(xrow) - wrow + fi(1, 0, 1, 0, fm), 0, 5, 0, fm);
ycol = fi(fi_signed(xcol) - wcol + fi(1, 0, 1, 0, fm), 0, 5, 0, fm);

y = fi(zeros(fi_toint(yrow), fi_toint(ycol), fi_toint(numFilters)), 1, 16, 8, fm);

    for k = fi(1, 0, 1, 0, fm):numFilters
    filter = fi(W(:, :, k), 1, 16, 15, fm);
    %filter = rot90(squeeze(filter), 2);
    %y(:, :, k) = conv2(x,filter, 'valid');
    y(:, :, k)=my_conv2_valid1(fi(x, 0, 16, 7, fm),fi(filter, 1, 16, 15, fm));
    end

end

function resultado = my_conv2_valid1(x, filtro)

    fm = get_fimath();

    resultado = fi(zeros(20, 20), 1, 16, 8, fm);

    % Aplicar el filtro bidimensional solo en las regiones válidas
    for i = 1:(20)
        for j = 1:(20)
            submatriz = fi(x(i:i+8, j:j+8), 0, 16, 8, fm);
            % Realizar la convolución para esta submatriz y almacenar el resultado
            resultado(i, j) = sum(sum(submatriz .* filtro));
        end
    end
end



function y = fi_signed(a)
    coder.inline( 'always' );
    if isfi( a ) && ~(issigned( a ))
        nt = numerictype( a );
        new_nt = numerictype( 1, nt.WordLength + 1, nt.FractionLength );
        y = fi( a, new_nt, fimath( a ) );
    else
        y = a;
    end
end


function y = fi_toint(u)
    coder.inline( 'always' );
    if isfi( u )
        nt = numerictype( u );
        s = nt.SignednessBool;
        wl = nt.WordLength;
        y = int32( fi( u, s, wl, 0, hdlfimath ) );
    else
        y = int32( u );
    end
end

function fm = get_fimath()
	fm = fimath('RoundingMethod', 'Zero',...
	     'OverflowAction', 'Wrap',...
	     'ProductMode','FullPrecision',...
	     'SumMode','FullPrecision');
end
